import { CodeHeader } from "./CodeHeader"

interface CodeBlockFrameProps {
  html: string
  code: string
  language?: string
  filename?: string
  filepath?: string
}

export function CodeBlockFrame({
  html,
  code,
  language = "ts",
  filename,
  filepath,
}: CodeBlockFrameProps) {
  return (
    <div className="overflow-hidden rounded-xl border border-white/10 bg-[#12141a] shadow-sm">
      <CodeHeader
        filename={filename}
        filepath={filepath}
        language={language}
        code={code}
      />

      <div
        className="docs-codeblock text-sm"
        dangerouslySetInnerHTML={{ __html: html }}
      />
    </div>
  )
}

export default CodeBlockFrame