"use client"

import { useState } from "react"
import { CodeBlockFrame } from "./CodeBlockFrame"

interface CodeExampleClientProps {
  language?: string
  filename?: string
  filepath: string
  snippet: string
  fullCode: string
  snippetHtml: string
  fullCodeHtml: string
  snippetTitle?: string
  fullFileTitle?: string
}

export function CodeExampleClient({
  language = "ts",
  filename,
  filepath,
  snippet,
  fullCode,
  snippetHtml,
  fullCodeHtml,
  snippetTitle = "Focused extract",
  fullFileTitle = "Full file",
}: CodeExampleClientProps) {
  const [expanded, setExpanded] = useState(false)

  return (
    <div className="my-8 overflow-hidden rounded-xl border border-white/10 bg-[#12141a] shadow-sm">
      <div className="sticky top-0 z-20 flex items-center justify-between gap-4 border-b border-white/10 bg-[#12141a]/95 px-4 py-3 text-sm backdrop-blur supports-[backdrop-filter]:bg-[#12141a]/80">
        <div className="min-w-0">
          <div className="font-medium text-white">
            {expanded ? fullFileTitle : snippetTitle}
          </div>
          <div className="truncate text-xs text-white/45">
            {filename ?? filepath}
          </div>
        </div>

        <button
          type="button"
          onClick={() => setExpanded((value) => !value)}
          className="shrink-0 rounded-md border border-white/10 bg-white/[0.04] px-3 py-1 text-xs text-white/70 transition-colors hover:bg-white/[0.07] hover:text-white"
        >
          {expanded ? "Revenir à l’extrait" : "Voir le fichier complet"}
        </button>
      </div>

      <div className="max-h-[70vh] overflow-auto">
        {expanded ? (
          <CodeBlockFrame
            html={fullCodeHtml}
            code={fullCode}
            language={language}
            filename={filename}
            filepath={filepath}
          />
        ) : (
          <CodeBlockFrame
            html={snippetHtml}
            code={snippet}
            language={language}
            filename={filename}
            filepath={filepath}
          />
        )}
      </div>
    </div>
  )
}

export default CodeExampleClient